import unittest

from memory_demo.visibility import visible_context_sections


class VisibilityHiddenTests(unittest.TestCase):
    def test_terminal_and_suppressed_excluded(self):
        sections = [
            {"name": "core", "status": "active"},
            {"name": "session", "status": "terminal"},
            {"name": "old", "status": "suppressed"},
            {"name": "stale", "status": "stale"},
        ]
        self.assertEqual(
            [section["name"] for section in visible_context_sections(sections)],
            ["core", "stale"],
        )


if __name__ == "__main__":
    unittest.main()
